try {
  const statsItems = $input.all();
  const business = $node['Split In Batches'].json;

  let totalReach = 0, totalEngagement = 0, totalImpressions = 0, roasSum = 0, roasCount = 0;
  for (const item of statsItems) {
    if (item.json.reach) totalReach += item.json.reach;
    if (item.json.engagement) totalEngagement += item.json.engagement;
    if (item.json.impressions) totalImpressions += item.json.impressions;
    if (item.json.roas) { roasSum += item.json.roas; roasCount++; }
  }

  return [{json: {
    business_id: business.id,
    business_name: business.business_name || '',
    email: business.email || '',
    total_reach: totalReach,
    total_engagement: totalEngagement,
    total_impressions: totalImpressions,
    avg_roas: roasCount > 0 ? (roasSum / roasCount).toFixed(2) : 0,
    posts_count: statsItems.length,
    report_month: new Date().toLocaleDateString('en-US', {month:'long', year:'numeric'})
  }}];
} catch(e) {
  return [{json:{error: e.message}}];
}

