try {
  const items = $input.all();
  const results = [];
  for (const item of items) {
    const responseContent = item.json.content && item.json.content[0] ? item.json.content[0].text : '{}';
    let parsed = {};
    try {
      parsed = JSON.parse(responseContent);
    } catch(e) {
      const match = responseContent.match(/\{[\s\S]*\}/);
      if (match) {
        try { parsed = JSON.parse(match[0]); } catch(e2) { parsed = {}; }
      }
    }
    const stats = $node['Compile Stats'].json;
    results.push({json: {
      business_id: stats.business_id,
      business_name: stats.business_name,
      email: stats.email,
      report_month: stats.report_month,
      total_reach: stats.total_reach,
      total_engagement: stats.total_engagement,
      total_impressions: stats.total_impressions,
      avg_roas: stats.avg_roas,
      posts_count: stats.posts_count,
      executive_summary: parsed.executive_summary || '',
      top_wins: parsed.top_wins || [],
      areas_for_improvement: parsed.areas_for_improvement || [],
      next_month_recommendations: parsed.next_month_recommendations || [],
      overall_score: parsed.overall_score || 0
    }});
  }
  return results;
} catch(e) {
  return [{json:{error: e.message}}];
}

